#[tokio::test]
async fn test_cookies_per_domain() {
    // Isolates cookies per domain during crawl
    let engine_config: CrawlConfig =
        serde_json::from_str("{\"cookies_enabled\":true,\"max_depth\":1,\"respect_robots_txt\":false}")
            .expect("config should parse");
    let engine = create_engine(Some(engine_config)).expect("handle creation should succeed");
    let url = std::env::var("MOCK_SERVER_COOKIES_PER_DOMAIN").unwrap_or_else(|_| {
        let _ = common::mock_server_url();
        std::env::var("MOCK_SERVER_COOKIES_PER_DOMAIN")
            .unwrap_or_else(|_| format!("{}/fixtures/{}", common::mock_server_url(), "cookies_per_domain"))
    });
    let result = crawl(&engine, &url).await.expect("should succeed");
    assert_eq!(result.cookies.len(), 1, "equals assertion failed");
    assert!(
        format!("{:?}", result.cookies).contains(r#"domain_cookie"#),
        "expected to contain: {}",
        r#"domain_cookie"#
    );
}

